&quot;, &amp;s, &amp;e, &amp;cost); g-&gt;edges[returnId(g, s)][returnId(g, e)] = cost; &#125; &#125; /* 根据图的邻接矩阵建立图的邻接表 */void CreateALGraph(MGragh *mg, ALGraph *alg)&#123; alg-&gt;n = mg-&gt;n; alg-&gt;e = mg-&gt;e; for (int i = 0; i&lt;alg-&gt;n; ++i) &#123; alg-&gt;adjlist[i].vertex = mg-&gt;vexs[i]; &#125; int i, j; EdgeNode *s; for (int i = 0; i &lt; alg-&gt;n; ++i) &#123; for (int j = 0; j &lt; alg-&gt;n; ++j) &#123; if (mg-&gt;edges[i][j] != 0) &#123; s = (EdgeNode*)malloc(sizeof(EdgeNode)); s-&gt;adjvex = j; s-&gt;Info = mg-&gt;edges[i][j]; s-&gt;next = NULL; EdgeNode*p = alg-&gt;adjlist[i].firstedge; s-&gt;next = p; alg-&gt;adjlist[i].firstedge = s; &#125; &#125; &#125;&#125; //打印图(邻接矩阵) void printGragh(MGragh *g)&#123; printf(&quot;
