&quot;); &#125; &#125; /**********************DFS*********************///从顶点v开始图(邻接矩阵)的深度遍历 void DFS_MG(MGragh *g, int v)&#123; int j; visited[v] = 1; printf(&quot;%c &quot;, g-&gt;vexs[v]); for (j = 0; j&lt;g-&gt;n; ++j) &#123; if (g-&gt;edges[v][j] != 0 &amp;&amp; !visited[j]) DFS_MG(g, j); &#125; &#125; //图的(邻接矩阵)的深度遍历 void DFSTranverse_MG(MGragh *g)&#123; int i; for (i = 0; i&lt;g-&gt;n; ++i)&#123; visited[i] = 0; //初始化访问数组visited的元素值为false &#125; for (i = 0; i&lt;g-&gt;n; ++i)&#123; if (!visited[i])&#123; //节点尚未访问 DFS_MG(g, i); &#125; &#125;&#125; //从顶点v开始图(邻接表)的深度遍历void DFS_ALG(ALGraph *g, int v)&#123; visited[v] = 1; printf(&quot;%c &quot;, g-&gt;adjlist[v].vertex); EdgeNode *p =g-&gt;adjlist[v].firstedge; while (p)&#123; if (!visited[p-&gt;adjvex])&#123; DFS_ALG(g, p-&gt;adjvex); //递归深度遍历 &#125; p = p-&gt;next; &#125; &#125; //图(邻接表)的深度遍历void DFSTranverse_ALG(ALGraph *g)&#123; int i; for (i = 0; i&lt;g-&gt;n; ++i)&#123; visited[i] = 0; //初始化访问数组visited的元素值为false &#125; for (i = 0; i&lt;g-&gt;n; ++i)&#123; if (!visited[i])&#123; //节点尚未访问 DFS_ALG(g, i); &#125; &#125;&#125; /**************************BFS****************************/ //从顶点v开始图(邻接矩阵)的广度遍历 void BFS_MG(MGragh *g, int v)&#123; int j; queue&lt;int&gt; Q; visited[v] = 1; printf(&quot;%c &quot;, g-&gt;vexs[v]); Q.push(v); while (!Q.empty()) &#123; v = Q.front(); Q.pop(); for (j = 0; j&lt;g-&gt;n; ++j) &#123; if (!visited[j] &amp;&amp; g-&gt;edges[v][j] !=0)// INFINITY) &#123; visited[j] = 1; printf(&quot;%c &quot;, g-&gt;vexs[j]); Q.push(j); &#125; &#125; &#125;&#125; //图(邻接矩阵)的广度遍历void BFSTranverse_MG(MGragh *g)&#123; int i; for (i = 0; i&lt;g-&gt;n; ++i)&#123; visited[i] = 0; //初始化访问数组visited的元素值为false &#125; for (i = 0; i&lt;g-&gt;n; ++i)&#123; if (!visited[i])&#123; //节点尚未访问 BFS_MG(g, i); &#125; &#125;&#125; //从顶点v开始图(邻接表)的广度遍历 void BFS_ALG(ALGraph *g, int v)&#123; queue&lt;int &gt; Q; visited[v] = 1; printf(&quot;%c &quot;, g-&gt;adjlist[v].vertex); Q.push(v); while (!Q.empty())&#123; v = Q.front(